class AppConfig:
    """Centralized, validated configuration from environment variables."""

    def __init__(self):
        self.storage_account_url = self._require_env("STORAGE_ACCOUNT_URL")
        self.source_container = self._require_env("SOURCE_CONTAINER_NAME")
        self.cosmos_endpoint = self._require_env("COSMOS_DB_ENDPOINT")
        self.cosmos_database = self._require_env("COSMOS_DATABASE_NAME")
        self.cosmos_container = self._require_env("COSMOS_CONTAINER_NAME")
        self.eventgrid_endpoint = self._require_env("EVENTGRID_TOPIC_ENDPOINT")

        # Optional: specify a user-assigned managed identity client ID
        # This avoids ambiguity when multiple identities are assigned
        self.managed_identity_client_id = os.environ.get(
            "AZURE_MANAGED_IDENTITY_CLIENT_ID"
        )

        # Allowed blob prefixes to prevent path traversal / unauthorized access
        self.allowed_blob_prefixes = self._parse_list_env(
            "ALLOWED_BLOB_PREFIXES", default=["incoming/"]
        )

        # Maximum blob size to process (prevent resource exhaustion)
        self.max_blob_size_bytes = int(
            os.environ.get("MAX_BLOB_SIZE_BYTES", str(50 * 1024 * 1024))  # 50 MB
        )

    @staticmethod
    def _require_env(name: str) -> str:
        value = os.environ.get(name)
        if not value:
            raise EnvironmentError(
                f"Required environment variable '{name}' is not set."
            )
        return value

    @staticmethod
    def _parse_list_env(name: str, default: list[str] | None = None) -> list[str]:
        raw = os.environ.get(name, "")
        if raw:
            return [item.strip() for item in raw.split(",") if item.strip()]
        return default or []


