class CredentialFactory:
    """
    Creates Azure credentials using Managed Identity.

    SECURITY BEST PRACTICES IMPLEMENTED:
    1. Uses ManagedIdentityCredential in production (not DefaultAzureCredential
       which falls through to environment variables, CLI, etc.)
    2. Supports user-assigned managed identity to avoid ambient authority issues.
    3. DefaultAzureCredential is only used in local development.
    """

    _credential = None

    @classmethod
    def get_credential(cls, client_id: Optional[str] = None):
        if cls._credential is None:
            environment = os.environ.get("AZURE_FUNCTIONS_ENVIRONMENT", "Production")

            if environment == "Development":
                logging.info("Using DefaultAzureCredential for local development.")
                cls._credential = DefaultAzureCredential()
            else:
                if client_id:
                    logging.info(
                        "Using user-assigned ManagedIdentityCredential."
                    )
                    cls._credential = ManagedIdentityCredential(
                        client_id=client_id
                    )
                else:
                    logging.info(
                        "Using system-assigned ManagedIdentityCredential."
                    )
                    cls._credential = ManagedIdentityCredential()

        return cls._credential


