class BlobValidator:
    """Validates blob paths and content to prevent injection and abuse."""

    @staticmethod
    def validate_blob_path(
        blob_name: str, allowed_prefixes: list[str]
    ) -> bool:
        """
        Validate blob name against allowed prefixes and path traversal.

        Prevents:
        - Path traversal attacks (../)
        - Access to blobs outside allowed prefixes
        - Null byte injection
        """
        if not blob_name:
            logging.warning("Empty blob name received.")
            return False

        # Check for null bytes
        if "\x00" in blob_name:
            logging.warning("Null byte detected in blob name: %s", blob_name)
            return False

        # Normalize and check for path traversal
        normalized = os.path.normpath(blob_name).replace("\\", "/")
        if ".." in normalized.split("/"):
            logging.warning("Path traversal attempt detected: %s", blob_name)
            return False

        # Check against allowed prefixes
        if allowed_prefixes:
            if not any(blob_name.startswith(prefix) for prefix in allowed_prefixes):
                logging.warning(
                    "Blob '%s' does not match any allowed prefix: %s",
                    blob_name,
                    allowed_prefixes,
                )
                return False

        return True

    @staticmethod
    def validate_blob_size(blob_size: int, max_size: int) -> bool:
        """Prevent processing of excessively large blobs (resource exhaustion)."""
        if blob_size > max_size:
            logging.warning(
                "Blob size %d exceeds maximum allowed size %d.",
                blob_size,
                max_size,
            )
            return False
        return True

    @staticmethod
    def compute_content_hash(content: bytes) -> str:
        """Compute SHA-256 hash for integrity verification."""
        return hashlib.sha256(content).hexdigest()


