class BlobStorageReader:
    """
    Reads blobs from Azure Blob Storage.

    REQUIRED ROLE: Storage Blob Data Reader (not Contributor!)
    Scope: Specific container, not the entire storage account.

    Role assignment command:
        az role assignment create \
            --assignee <managed-identity-object-id> \
            --role "Storage Blob Data Reader" \
            --scope "/subscriptions/<sub>/resourceGroups/<rg>/providers/
                     Microsoft.Storage/storageAccounts/<account>/
                     blobServices/default/containers/<container>"
    """

    def __init__(self, config: AppConfig, credential):
        self._client = BlobServiceClient(
            account_url=config.storage_account_url,
            credential=credential,
        )
        self._container_name = config.source_container
        self._config = config

    def read_blob(self, blob_name: str) -> Optional[bytes]:
        """Read blob content with validation."""
        if not BlobValidator.validate_blob_path(
            blob_name, self._config.allowed_blob_prefixes
        ):
            raise ValueError(f"Blob path validation failed: {blob_name}")

        container_client = self._client.get_container_client(
            self._container_name
        )
        blob_client = container_client.get_blob_client(blob_name)

        # Check blob properties before downloading
        properties = blob_client.get_blob_properties()
        blob_size = properties.size

        if not BlobValidator.validate_blob_size(
            blob_size, self._config.max_blob_size_bytes
        ):
            raise ValueError(
                f"Blob '{blob_name}' exceeds maximum size "
                f"({blob_size} > {self._config.max_blob_size_bytes})."
            )

        download = blob_client.download_blob()
        content = download.readall()

        logging.info(
            "Read blob '%s' (%d bytes, SHA-256: %s)",
            blob_name,
            len(content),
            BlobValidator.compute_content_hash(content)[:16] + "...",
        )

        return content


class CosmosDBWriter:
    """
    Writes processed results to Cosmos DB.

    REQUIRED ROLE: Custom role with ONLY data-plane actions:
        - Microsoft.DocumentDB/databaseAccounts/readMetadata
        - Microsoft.DocumentDB/databaseAccounts/sqlDatabases/containers/items/*

    DO NOT USE: "Cosmos DB Account Contributor" — this is a management-plane role
    that allows deleting databases, modifying account settings, managing keys, etc.

    For built-in roles, use "Cosmos DB Built-in Data Contributor" (data plane):
        az cosmosdb sql role assignment create \
            --account-name <account> \
            --resource-group <rg> \
            --scope "/" \
            --principal-id <managed-identity-object-id> \
            --role-definition-id "00000000-0000-0000-0000-000000000002"
    """

    def __init__(self, config: AppConfig, credential):
        self._client = CosmosClient(
            url=config.cosmos_endpoint,
            credential=credential,
        )
        self._database = self._client.get_database_client(
            config.cosmos_database
        )
        self._container = self._database.get_container_client(
            config.cosmos_container
        )

    def write_result(self, document: dict[str, Any]) -> dict[str, Any]:
        """
        Write a processed result document to Cosmos DB.

        Validates document structure before writing.
        """
        self._validate_document(document)

        # Add metadata
        document["_processedAt"] = datetime.now(timezone.utc).isoformat()
        document["_schemaVersion"] = "1.0"

        try:
            result = self._container.upsert_item(body=document)
            logging.info(
                "Wrote document '%s' to Cosmos DB.", document.get("id")
            )
            return result
        except cosmos_exceptions.CosmosHttpResponseError as e:
            logging.error("Cosmos DB write failed: %s", e.message)
            raise

    @staticmethod
    def _validate_document(document: dict[str, Any]) -> None:
        """Validate document structure before writing."""
        if "id" not in document:
            raise ValueError("Document must contain an 'id' field.")

        if not isinstance(document["id"], str):
            raise ValueError("Document 'id' must be a string.")

        # Prevent excessively large documents
        doc_size = len(json.dumps(document).encode("utf-8"))
        max_doc_size = 2 * 1024 * 1024  # 2 MB Cosmos DB limit
        if doc_size > max_doc_size:
            raise ValueError(
                f"Document size ({doc_size}) exceeds Cosmos DB limit ({max_doc_size})."
            )


class EventGridNotifier:
    """
    Sends notifications via Azure Event Grid.

    REQUIRED ROLE: Event Grid Data Sender
    Scope: Specific Event Grid topic, not the entire resource group.

    Role assignment command:
        az role assignment create \
            --assignee <managed-identity-object-id> \
            --role "EventGrid Data Sender" \
            --scope "/subscriptions/<sub>/resourceGroups/<rg>/providers/
                     Microsoft.EventGrid/topics/<topic>"
    """

    def __init__(self, config: AppConfig, credential):
        self._client = EventGridPublisherClient(
            endpoint=config.eventgrid_endpoint,
            credential=credential,
        )

    def send_notification(
        self,
        event_type: str,
        subject: str,
        data: dict[str, Any],
        source: str = "/azure-function/blob-processor",
    ) -> None:
        """Send a CloudEvent notification."""
        # Sanitize event data — remove any sensitive fields
        sanitized_data = self._sanitize_event_data(data)

        event = CloudEvent(
            type=event_type,
            source=source,
            subject=subject,
            data=sanitized_data,
        )

        self._client.send([event])
        logging.info(
            "Sent Event Grid notification: type=%s, subject=%s",
            event_type,
            subject,
        )

    @staticmethod
    def _sanitize_event_data(data: dict[str, Any]) -> dict[str, Any]:
        """
        Remove sensitive fields from event data before publishing.

        Events may be consumed by multiple subscribers — never include
        secrets, tokens, PII, or raw file content in events.
        """
        sensitive_keys = {
            "password", "secret", "token", "key", "authorization",
            "content", "raw_data", "ssn", "email", "phone",
        }
        sanitized = {}
        for k, v in data.items():
            if k.lower() in sensitive_keys:
                sanitized[k] = "[REDACTED]"
            elif isinstance(v, dict):
                sanitized[k] = EventGridNotifier._sanitize_event_data(v)
            else:
                sanitized[k] = v
        return sanitized


