class FileProcessor:
    """Processes blob content and produces a result document."""

    SUPPORTED_CONTENT_TYPES = {"application/json", "text/csv", "text/plain"}

    @classmethod
    def process(
        cls, blob_name: str, content: bytes, content_type: str = "application/json"
    ) -> dict[str, Any]:
        """
        Process file content and return a result document.

        Replace this with your actual business logic.
        """
        if content_type not in cls.SUPPORTED_CONTENT_TYPES:
            raise ValueError(f"Unsupported content type: {content_type}")

        content_hash = BlobValidator.compute_content_hash(content)

        # Generate a deterministic document ID from blob name + content hash
        doc_id = hashlib.sha256(
            f"{blob_name}:{content_hash}".encode()
        ).hexdigest()[:32]

        result = {
            "id": doc_id,
            "sourceBlobName": blob_name,
            "contentHash": content_hash,
            "contentSizeBytes": len(content),
            "contentType": content_type,
            "status": "processed",
            "processingTimestamp": datetime.now(timezone.utc).isoformat(),
        }

        # --- Your business logic here ---
        if content_type == "application/json":
            try:
                parsed = json.loads(content)
                result["recordCount"] = (
                    len(parsed) if isinstance(parsed, list) else 1
                )
            except json.JSONDecodeError as e:
                result["status"] = "error"
                result["errorMessage"] = f"Invalid JSON: {e}"
        elif content_type == "text/csv":
            lines = content.decode("utf-8", errors="replace").strip().split("\n")
            result["recordCount"] = max(0, len(lines) - 1)  # Exclude header
        else:
            result["recordCount"] = 1

        return result


