app = func.FunctionApp()


@app.blob_trigger(
    arg_name="blob",
    path="{SOURCE_CONTAINER_NAME}/{name}",
    connection="STORAGE_CONNECTION",
)
def process_blob(blob: func.InputStream) -> None:
    """
    Azure Function triggered by new blobs in the source container.

    Security measures:
    1. Input validation (blob path, size, content type)
    2. Managed Identity with least-privilege roles
    3. Event data sanitization
    4. Structured error handling (no sensitive data in logs)
    """
    blob_name = blob.name or ""
    logging.info("Processing blob: %s", blob_name)

    try:
        # Initialize configuration and credentials
        config = AppConfig()
        credential = CredentialFactory.get_credential(
            client_id=config.managed_identity_client_id
        )

        # Strip container prefix from blob name if present
        if "/" in blob_name:
            # blob.name may come as "container/path/to/file"
            parts = blob_name.split("/", 1)
            if parts[0] == config.source_container:
                blob_name = parts[1]

        # Validate blob path
        if not BlobValidator.validate_blob_path(
            blob_name, config.allowed_blob_prefixes
        ):
            logging.error("Blob path validation failed. Skipping: %s", blob_name)
            return

        # Read blob content (via trigger input stream for efficiency)
        content = blob.read()

        if not BlobValidator.validate_blob_size(
            len(content), config.max_blob_size_bytes
        ):
            logging.error("Blob too large. Skipping: %s", blob_name)
            return

        # Determine content type
        content_type = getattr(blob, "content_type", None) or "application/json"

        # Process the file
        result = FileProcessor.process(blob_name, content, content_type)

        # Write result to Cosmos DB
        cosmos_writer = CosmosDBWriter(config, credential)
        cosmos_writer.write_result(result)

        # Send notification via Event Grid
        notifier = EventGridNotifier(config, credential)
        notifier.send_notification(
            event_type="BlobProcessor.FileProcessed",
            subject=f"/blobs/{blob_name}",
            data={
                "blobName": blob_name,
                "status": result["status"],
                "documentId": result["id"],
                "recordCount": result.get("recordCount", 0),
                "contentSizeBytes": result["contentSizeBytes"],
            },
        )

        logging.info(
            "Successfully processed blob '%s' -> document '%s'.",
            blob_name,
            result["id"],
        )

    except EnvironmentError as e:
        logging.critical("Configuration error: %s", e)
        raise

    except ValueError as e:
        logging.error("Validation error processing '%s': %s", blob_name, e)
        # Don't re-raise validation errors — the blob won't become valid on retry

    except Exception:
        logging.exception("Unexpected error processing blob '%s'.", blob_name)
        raise  # Re-raise to trigger Azure Functions retry policy


